import { makeSimpleQuestion } from './base'
import type { Question, Topic } from './types'

const SOURCE = 'Floe career agent-generated healthcare roadmap top-off bank'
const DEFAULT_FLAW = 'This is a plausible distractor, but it does not match the scenario or roadmap concept.'

function q(
  id: number,
  topic: Topic,
  chapter: string,
  title: string,
  prompt: string,
  correct: string,
  wrong: string[],
  lesson: string,
): Question {
  return makeSimpleQuestion(
    id,
    topic,
    chapter,
    title,
    prompt,
    correct,
    wrong.map((label) => [label, DEFAULT_FLAW, lesson] as [string, string, string]),
    lesson,
    SOURCE,
  )
}

type Item = [
  chapter: string,
  title: string,
  prompt: string,
  correct: string,
  wrong: string[],
  lesson: string,
]

function build(startId: number, topic: Topic, items: Item[]): Question[] {
  return items.map(([chapter, title, prompt, correct, wrong, lesson], index) =>
    q(startId + index, topic, chapter, title, prompt, correct, wrong, lesson),
  )
}

